parameters.jsCode:
// TRUY CẬP CHÍNH XÁC VÀO LỚP 'output'
const input_data = items[0].json.output; 

// Kiểm tra xem dữ liệu có tồn tại không trước khi đọc thuộc tính
if (!input_data || !input_data.technical_questions || !input_data.soft_skills_questions) {
    // Thông báo lỗi nếu cấu trúc JSON không đúng
    throw new Error("Dữ liệu đầu ra từ Structured Output Parser không đúng định dạng JSON yêu cầu.");
}

const technicalQuestions = input_data.technical_questions;
const softSkillQuestions = input_data.soft_skills_questions;

// 1. Tạo chuỗi cho câu hỏi Kỹ thuật
let technicalString = "### CÂU HỎI KỸ THUẬT (Technical Questions):\n";
technicalQuestions.forEach((item, index) => {
    technicalString += `${index + 1}. ${item.question}\n`;
});

// 2. Tạo chuỗi cho câu hỏi Kỹ năng mềm
let softSkillString = "\n### CÂU HỎI KỸ NĂNG MỀM (Soft Skills Questions):\n";
softSkillQuestions.forEach((item, index) => {
    softSkillString += `${index + 1}. ${item.question}\n`;
});

// 3. Ghép nối hai chuỗi
const combinedList = technicalString + softSkillString;

// Trả về đối tượng mới để Google Sheet sử dụng
return [{
  json: {
    question_for_candidate: combinedList
  }
}];

const pages = [];
let fullText = "";

items.forEach((it, idx) => {
  const resp = it.json;
  let text = "";

  if (resp.output_text) {
    text = resp.output_text;
  } else if (resp.output) {
    for (const o of resp.output) {
      if (o.content) {
        for (const c of o.content) {
          if (c.type === 'output_text' && c.text) {
            text += c.text + "\n";
          }
        }
      }
    }
  }

  text = text.trim();

  pages.push({
    page: idx,    // page 0,1,2...
    text
  });

  // Giữ lại phần này nếu bạn vẫn muốn đánh dấu trang trong fullText
  fullText += `--- Page ${idx} ---\n${text}\n\n`;
});

// THAY ĐỔI Ở ĐÂY: Chỉ trả về một object với key là 'text'
return {
  text: fullText.trim()
};

