// items[0].json.urls assumed
const arr = items[0].json.urls || [];
return arr.map((u, i) => ({ json: { page: i+1, url: u } }));

// Prepare RAG Sections
const sectionsResults = [];

// Get Resume Content from 'candidate CV1' node
const candidateItems = $('candidate CV1').all();

for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const aiOutput = item.json.output || {};
    const candidateItem = candidateItems[i] ? candidateItems[i].json : {};
    // IMPORTANT: Source of truth is the RAW resume content
    const resumeContent = candidateItem.resume_content || "";

    // Get Name
    let candidateName = aiOutput['Họ tên ứng viên'];
    if (!candidateName && resumeContent) {
        candidateName = resumeContent.split('\n')[0].trim();
    }
    candidateName = candidateName || "Unknown Candidate";

    // Sanitize ID
    const docIdRoot = candidateName.replace(/[^a-zA-Z0-9]/g, "_");

    // 1. RAW CV SECTIONS
    if (resumeContent) {
        const headerPattern = /^(SUMMARY|EXPERIENCE|EDUCATION|CERTIFICATIONS|SKILLS|PROJECTS|TÓM TẮT|KINH NGHIỆM|HỌC VẤN|KỸ NĂNG|DỰ ÁN|REFERENCES|NGƯỜI THAM CHIẾU)(?:[:]?)$/i;

        const lines = resumeContent.split('\n');
        let currentSectionName = "INFO"; 
        let currentBuffer = [];

        for (const line of lines) {
            const trimmedLine = line.trim();
            if (!trimmedLine) continue;

            if (headerPattern.test(trimmedLine)) {
                 if (currentBuffer.length > 0) {
                     const secText = `[${candidateName}] - ${currentSectionName}:\n` + currentBuffer.join('\n');
                     sectionsResults.push({
                        json: {
                            payload: {
                                text: secText,
                                file_name: candidateName,
                                candidate_name: candidateName,
                                section_name: currentSectionName,
                                doc_id: `${docIdRoot}_${currentSectionName.toLowerCase()}`
                            }
                        }
                     });
                 }
                 currentSectionName = trimmedLine.toUpperCase().replace(/[:]/g, '');
                 currentBuffer = [];
            } else {
                currentBuffer.push(trimmedLine);
            }
        }

        if (currentBuffer.length > 0) {
             const secText = `[${candidateName}] - ${currentSectionName}:\n` + currentBuffer.join('\n');
             sectionsResults.push({
                json: {
                    payload: {
                        text: secText,
                        file_name: candidateName,
                        candidate_name: candidateName,
                        section_name: currentSectionName,
                        doc_id: `${docIdRoot}_${currentSectionName.toLowerCase()}`
                    }
                }
             });
        }
    }
}

return sectionsResults;
